#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelGeluCustom {
public:
    __aicore__ inline KernelGeluCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        // UB layout:
        //   inQueueX  : 2 * tile  (input)
        //   outQueueY : 2 * tile  (output)
        //   tmpQueue  : 5 * tile  (intermediate storage)
        // Total needed: 9 * tile floats
        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 5, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        // Tile-granularity grid-stride to improve load balance and occupancy.
        const uint32_t strideElems = blockNum * tileLen_;
        uint32_t base = blockIdx * tileLen_;
        if (base >= totalLen_) return;

        // Prefetch first tile
        uint32_t curLen = totalLen_ - base;
        if (curLen > tileLen_) curLen = tileLen_;
        CopyIn(base, curLen);

        while (true) {
            // Prefetch next tile early for overlap
            const uint32_t nextBase = base + strideElems;
            uint32_t nextLen = 0;
            if (nextBase < totalLen_) {
                nextLen = totalLen_ - nextBase;
                if (nextLen > tileLen_) nextLen = tileLen_;
                CopyIn(nextBase, nextLen);
            }

            Compute(curLen);
            CopyOut(base, curLen);

            if (nextLen == 0) break;
            base = nextBase;
            curLen = nextLen;
        }
    }

private:
    __aicore__ inline void CopyIn(uint32_t gmOffset, uint32_t len)
    {
        AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
        AscendC::DataCopy(xLocal, xGm_[gmOffset], len);
        inQueueX_.EnQue(xLocal);
    }

    __aicore__ inline void Compute(uint32_t len)
    {
        AscendC::LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
        AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();

        // tmp tensors for intermediate results
        AscendC::LocalTensor<float> t1 = tmpQueue_.AllocTensor<float>();  // x^2
        AscendC::LocalTensor<float> t2 = tmpQueue_.AllocTensor<float>();  // x^3
        AscendC::LocalTensor<float> t3 = tmpQueue_.AllocTensor<float>();  // poly = x + c*x^3
        AscendC::LocalTensor<float> t4 = tmpQueue_.AllocTensor<float>();  // scaled = k * poly
        AscendC::LocalTensor<float> t5 = tmpQueue_.AllocTensor<float>();  // tanh result

        // Constants for GELU approximation: 0.5 * x * (1 + tanh(sqrt(2/pi) * (x + 0.044715*x^3)))
        // Using 0.7978845608 = sqrt(2/pi)
        // Using 0.044715 as the cubic coefficient

        // Step 1: t1 = x * x (x squared)
        AscendC::Muls(t1, xLocal, xLocal, len);

        // Step 2: t2 = t1 * x (x cubed)
        AscendC::Muls(t2, t1, xLocal, len);

        // Step 3: t3 = c * x^3 where c = 0.044715
        AscendC::Muls(t3, t2, 0.044715f, len);

        // Step 4: t3 = x + c*x^3 (the polynomial)
        AscendC::Adds(t3, t3, xLocal, len);

        // Step 5: t4 = k * poly where k = sqrt(2/pi) = 0.7978845608
        AscendC::Muls(t4, t3, 0.7978845608f, len);

        // Step 6: t5 = tanh(t4) - use yLocal as temporary, then move to t5
        AscendC::Tanh(yLocal, t4, tmpQueueBuf_, len);

        // Free t4 as we need the buffer space
        // Actually, we need to compute: 0.5 * x * (1 + tanh_result)
        // Let's compute in yLocal directly

        // Step 7: yLocal = 1 + tanh(t4)
        AscendC::Adds(yLocal, yLocal, 1.0f, len);

        // Step 8: yLocal = 0.5 * (1 + tanh)
        AscendC::Muls(yLocal, yLocal, 0.5f, len);

        // Step 9: yLocal = x * 0.5 * (1 + tanh) = GELU(x)
        AscendC::Muls(yLocal, yLocal, xLocal, len);

        // Free all temporary tensors
        tmpQueue_.FreeTensor(t1);
        tmpQueue_.FreeTensor(t2);
        tmpQueue_.FreeTensor(t3);
        tmpQueue_.FreeTensor(t4);
        tmpQueue_.FreeTensor(t5);

        outQueueY_.EnQue<float>(yLocal);
        inQueueX_.FreeTensor(xLocal);
    }

    __aicore__ inline void CopyOut(uint32_t gmOffset, uint32_t len)
    {
        AscendC::LocalTensor<float> yLocal = outQueueY_.DeQue<float>();
        AscendC::DataCopy(yGm_[gmOffset], yLocal, len);
        outQueueY_.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 5> tmpQueue_;
    AscendC::LocalTensor<uint8_t> tmpQueueBuf_;  // for Tanh shared buffer

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
};

